exec rs_rptStockCardAllItems @tu_ngay, @den_ngay, @ma_kho, @ma_vt, @nh_vt1, @nh_vt2, @nh_vt3, @tk_vt, @loai_vt, @ma_dvcs, @loai_du_lieu, @@language, @@userID, @@admin, '&Controller;', '@@sysDatabaseName', '#$query'







      &JavascriptReportFilter;
      &OutlineEntry;
      &ScriptQueryFilterString;
      &SetReportFormLimitRight;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  var a = ['ma_kho'];
  if (!f._extensions) f.request('GetDefaultValue', 'SetDefaultValue', a);
    else setReferenceValue(f, a);
  if (!f.getItemValue('ngay3')) f.setItemValue('ngay3', new Date());
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, dFrom = f.getItem('tu_ngay').value, dTo = f.getItem('den_ngay').value, x = f.getItemValue('mau_bc'), r = f.getItemValue('kieu_bc'), c = f.getItemValue('chon_tt');
      g._alterTitle = [null, [['%d1', dFrom, true], ['%d2', dTo, true], ['%s1', f.getItemValue('ma_kho'), true], ['%s2', f.getItemValue('ten_kho%l'), true]]];
      g._hiddenFields = [
        {Fields: 'du_dau, tien_nhap, tien_xuat, du_cuoi', Value: (x == '10')},
        {Fields: 'du_dau_nt, tien_nt_n, tien_nt_x, du_cuoi_nt', Value: (x == '10' || x == '20')}
      ];

      if (f._hidden$GridForm) {
        g._hiddenForms = [
          {Form: f._hidden$GridForm, Value: 1},
          {Form: [0, 14], Value: (r == '1') || (c != '1')},
          {Form: [1, 15], Value: (r == '2') || (c != '1')}
        ];
      } else {
        g._hiddenForms = [
          {Form: [0, 5, 7, 14, 17, 18], Value: (r == '1') || (c != '1')},
          {Form: [2, 9, 11, 15, 19, 20], Value: (r == '2') || (c != '1')},
          {Form: [13, 16], Value: (c != '1')},
          {Form: [1, 6, 8], Value: (r == '1') || (c == '1')},
          {Form: [3, 10, 12], Value: (r == '2') || (c == '1')}
        ];
      }

      g._queryFilterString = getQueryFilterString(f, 'ma_kho, tu_ngay, den_ngay, ma_dvcs, loai_du_lieu, mau_bc, tk_vt');
      if (g._$k != null) g._$k = [];
      remove$GridReport$Filter(g);
      break;
    case 'SetDefaultValue':
      f.setItemControlBehavior('ten_kho%l', result[0].Value, null, true);
      if (result[0].Value == '') f.setItemValue('ma_kho', '');
      break;
    default:
      break;
  }
}
function setReferenceValue(f, a) {
  for (var i = 0; i < a.length; i++) {
    var r = $func.findField(a[i], f._fields).ItemReference;
    f.setItemValue(r, $func.findMemvar(r, f._extensions).NewValue);
  }
}/* </flatten> */








